import sqlite3

# Connect to the SQLite database. It will be created if it doesn't exist.
conn = sqlite3.connect('users.db')
cursor = conn.cursor()

# Create a table for storing usernames and passwords. 
# This is insecure as it stores plaintext passwords, but suitable for a simple prototype.
def create_table():
    cursor.execute("""
        CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY,
            username TEXT UNIQUE,
            password TEXT
        )
    """)

create_table()

def register_user(username, password):
    cursor.execute("INSERT INTO users (username, password) VALUES (?, ?)", (username, password))
    conn.commit()

def login_user(username, password):
    cursor.execute("SELECT * FROM users WHERE username = ? AND password = ?", (username, password))
    if len(cursor.fetchall()) > 0:
        return True
    else:
        return False

# Example usage:
register_user('user1', 'password1')
print(login_user('user1', 'password1'))  # Should print: True